from itertools import combinations
class Solution:
    def maxArea(self, coords):
        best = -1
        for a, b, c in combinations(coords, 3):
            axis = (a[0] == b[0] or b[0] == c[0] or a[0] == c[0] or
                    a[1] == b[1] or b[1] == c[1] or a[1] == c[1])
            if not axis:
                continue
            twice = abs((b[0] - a[0]) * (c[1] - a[1]) - (c[0] - a[0]) * (b[1] - a[1]))
            if twice == 0:
                continue
            if twice > best:
                best = twice
        return best

