class Solution:
    def maxArea(self, coords):
        min_x = min(p[0] for p in coords)
        max_x = max(p[0] for p in coords)
        min_y = min(p[1] for p in coords)
        max_y = max(p[1] for p in coords)
        by_x = {}
        by_y = {}
        for x, y in coords:
            if x in by_x:
                lo, hi = by_x[x]
                by_x[x] = (min(lo, y), max(hi, y))
            else:
                by_x[x] = (y, y)
            if y in by_y:
                lo, hi = by_y[y]
                by_y[y] = (min(lo, x), max(hi, x))
            else:
                by_y[y] = (x, x)
        best = -1
        for x, (lo, hi) in by_x.items():
            base = hi - lo
            if base == 0:
                continue
            height = max(max_x - x, x - min_x)
            if height == 0:
                continue
            best = max(best, base * height)
        for y, (lo, hi) in by_y.items():
            base = hi - lo
            if base == 0:
                continue
            height = max(max_y - y, y - min_y)
            if height == 0:
                continue
            best = max(best, base * height)
        return best

