var maxArea = function(coords) {
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    for (const [x, y] of coords) {
        if (x < minX) minX = x;
        if (x > maxX) maxX = x;
        if (y < minY) minY = y;
        if (y > maxY) maxY = y;
    }
    const byX = new Map(), byY = new Map();
    for (const [x, y] of coords) {
        if (byX.has(x)) { const v = byX.get(x); v[0] = Math.min(v[0], y); v[1] = Math.max(v[1], y); }
        else byX.set(x, [y, y]);
        if (byY.has(y)) { const v = byY.get(y); v[0] = Math.min(v[0], x); v[1] = Math.max(v[1], x); }
        else byY.set(y, [x, x]);
    }
    let best = -1;
    for (const [x, [lo, hi]] of byX) {
        const base = hi - lo;
        if (base === 0) continue;
        const height = Math.max(maxX - x, x - minX);
        if (height === 0) continue;
        best = Math.max(best, base * height);
    }
    for (const [y, [lo, hi]] of byY) {
        const base = hi - lo;
        if (base === 0) continue;
        const height = Math.max(maxY - y, y - minY);
        if (height === 0) continue;
        best = Math.max(best, base * height);
    }
    return best;
};
